mapper.insert:
/** CmmtSurveyMemberAnsDao.insertList */
insert into cmmt_survey_member_ans (
	 member_ans_id
	,survey_id
	,question_id
	,answer_id
	,member_id
	,short_answer
	,created_dt
) values

	(
		 #{item.memberAnsId}
		,#{item.surveyId}
		,#{item.questionId}
		,#{item.answerId}
		,#{item.memberId}
		,#{item.shortAnswer}
		,#{item.createdDt}
	)

mapper.select:
/** CmmtSurveyMemberAnsDao.existsSurveyAns */
select
	exists (
		select
			member_ans_id
		from
			cmmt_survey_member_ans
		where
			survey_id =  #{surveyId}
	)

/** CmmtSurveyMemberAnsDao.existsMember */
select
	exists (
		select
			member_ans_id
		from
			cmmt_survey_member_ans
		where
			survey_id =  #{surveyId}
			and member_id = #{memberId}
	)
